-- =============================================================================
-- Sonar · PostgreSQL incremental migration
-- V202607201200__v0.3.x_Overview_Queries.pg.sql
-- =============================================================================
-- Seeds the 3 Overview stored Queries (Sonar: Band Trend / Band Flows / Score
-- Movers) in PostgreSQL dialect. These were deliberately NOT included in the
-- baseline (B202607171700) because their bodies are T-SQL and fail on PG; this
-- migration closes that documented gap, bringing the Overview analytics to
-- feature parity with SQL Server.
--
-- What changed vs the T-SQL originals (dialect only — same IDs, params, fields):
--   CONVERT(date, x)            -> x::date
--   CONVERT(varchar(10),d,23)   -> to_char(d,'YYYY-MM-DD')
--   CONVERT(varchar(36),uuid)   -> uuid::text
--   ISNULL(a,b)                 -> COALESCE(a,b)
--   ROUND(x,0) on float         -> ROUND(x::numeric,0)::int
--   [schema].[Table]            -> __mj_bizappssonar."Table"
--   date = '{{param}}'          -> date = ('{{param}}')::date  (explicit cast)
--   SQLDialectID -> PostgreSQL (426915F2…) instead of T-SQL (1F203987…)
--
-- ENTITY FKs BY NAME: QueryEntity.EntityID and QueryField.SourceEntityID are
-- resolved with (SELECT "ID" FROM __mj."Entity" WHERE "Name"=…) rather than a
-- hardcoded id. The Sonar entity IDs differ between the SQL Server seed and the
-- PG baseline (CodeGen minted fresh ids on PG; they were not preserved), so a
-- literal SQL-Server id would FK-violate here. Entity NAMES are stable across
-- both, so name resolution is correct and survives a baseline regen.
--
-- The {{ ModelID | sqlString }} etc. are MJ Query template params, resolved by
-- the query engine before the DB sees them — platform-agnostic, left as-is.
--
-- Idempotent: every row is INSERT ... ON CONFLICT ("ID") DO NOTHING.
-- =============================================================================

INSERT INTO __mj."Query" ("ID", "Name", "CategoryID", "UserQuestion", "Description", "SQL", "TechnicalDescription", "OriginalSQL", "Feedback", "Status", "QualityRank", "ExecutionCostRank", "__mj_CreatedAt", "__mj_UpdatedAt", "UsesTemplate", "AuditQueryRuns", "CacheEnabled", "CacheTTLMinutes", "CacheMaxSize", "EmbeddingVector", "EmbeddingModelID", "CacheValidationSQL", "SQLDialectID", "Reusable", "ExternalDataSourceID") VALUES ('5044A100-0020-4000-8000-000000000002', 'Sonar: Band Flows', NULL, NULL, 'Band-change cohorts between two snapshot days for a model: one row per (from band, to band) with the member count, biggest first. Members present at only one of the two days are skipped (not a band CHANGE). Powers the Overview migration ribbons and the ''who needs action'' cohort chips at any look-back window.', 'WITH snap AS (
    SELECT h."AnchorRecordID", h."BandID",
        COALESCE(h."AsOfDate", h."ComputedAt")::date AS "SnapshotDay",
        ROW_NUMBER() OVER (PARTITION BY h."AnchorRecordID", COALESCE(h."AsOfDate", h."ComputedAt")::date ORDER BY h."AsOfDate" DESC, h."ComputedAt" DESC) AS rn
    FROM __mj_bizappssonar."ScoreHistory" h
    WHERE h."ScoreModelID" = {{ ModelID | sqlString }}
      AND COALESCE(h."AsOfDate", h."ComputedAt")::date IN (({{ FromDay | sqlString }})::date, ({{ ToDay | sqlString }})::date)
)
SELECT f."BandID"::text AS "FromBandID",
       COALESCE(fb."Label", ''Unbanded'') AS "FromBand",
       t."BandID"::text AS "ToBandID",
       COALESCE(tb."Label", ''Unbanded'') AS "ToBand",
       COUNT(*)::int AS "MemberCount"
FROM snap f
JOIN snap t ON t."AnchorRecordID" = f."AnchorRecordID" AND t."SnapshotDay" = ({{ ToDay | sqlString }})::date AND t.rn = 1
LEFT JOIN __mj_bizappssonar."ScoreBand" fb ON fb."ID" = f."BandID"
LEFT JOIN __mj_bizappssonar."ScoreBand" tb ON tb."ID" = t."BandID"
WHERE f."SnapshotDay" = ({{ FromDay | sqlString }})::date AND f.rn = 1
  AND COALESCE(f."BandID"::text, '''') <> COALESCE(t."BandID"::text, '''')
GROUP BY f."BandID", COALESCE(fb."Label", ''Unbanded''), t."BandID", COALESCE(tb."Label", ''Unbanded'')
ORDER BY COUNT(*) DESC', NULL, 'WITH snap AS (
    SELECT h."AnchorRecordID", h."BandID",
        COALESCE(h."AsOfDate", h."ComputedAt")::date AS "SnapshotDay",
        ROW_NUMBER() OVER (PARTITION BY h."AnchorRecordID", COALESCE(h."AsOfDate", h."ComputedAt")::date ORDER BY h."AsOfDate" DESC, h."ComputedAt" DESC) AS rn
    FROM __mj_bizappssonar."ScoreHistory" h
    WHERE h."ScoreModelID" = {{ ModelID | sqlString }}
      AND COALESCE(h."AsOfDate", h."ComputedAt")::date IN (({{ FromDay | sqlString }})::date, ({{ ToDay | sqlString }})::date)
)
SELECT f."BandID"::text AS "FromBandID",
       COALESCE(fb."Label", ''Unbanded'') AS "FromBand",
       t."BandID"::text AS "ToBandID",
       COALESCE(tb."Label", ''Unbanded'') AS "ToBand",
       COUNT(*)::int AS "MemberCount"
FROM snap f
JOIN snap t ON t."AnchorRecordID" = f."AnchorRecordID" AND t."SnapshotDay" = ({{ ToDay | sqlString }})::date AND t.rn = 1
LEFT JOIN __mj_bizappssonar."ScoreBand" fb ON fb."ID" = f."BandID"
LEFT JOIN __mj_bizappssonar."ScoreBand" tb ON tb."ID" = t."BandID"
WHERE f."SnapshotDay" = ({{ FromDay | sqlString }})::date AND f.rn = 1
  AND COALESCE(f."BandID"::text, '''') <> COALESCE(t."BandID"::text, '''')
GROUP BY f."BandID", COALESCE(fb."Label", ''Unbanded''), t."BandID", COALESCE(tb."Label", ''Unbanded'')
ORDER BY COUNT(*) DESC', NULL, 'Approved', 0, NULL, '2026-07-09T20:32:36.966Z', '2026-07-09T20:36:38.883Z', TRUE, FALSE, FALSE, NULL, NULL, '[-0.035168152302503586,0.057255085557699203,-0.03535761684179306,-0.0870850533246994,-0.018599221482872963,-0.03515934944152832,0.01971188373863697,-0.02948172576725483,-0.036064859479665756,0.06130122393369675,0.020216254517436028,-0.05750184506177902,-0.025721093639731407,0.09995430707931519,-0.003691047430038452,-0.006001697387546301,0.028358856216073036,-0.046645838767290115,-0.03955191373825073,-0.0038083207327872515,-0.04567950963973999,-0.03539252653717995,-0.009553148411214352,-0.02801625430583954,0.06146895885467529,-0.015806013718247414,-0.0709313452243805,0.050916992127895355,0.03714022412896156,-0.07783268392086029,0.02208700403571129,0.05821825936436653,-0.004252105485647917,0.02053455263376236,0.0000022510978396894643,-0.0108199967071414,-0.026441359892487526,-0.003958967048674822,-0.03788106516003609,0.0034750024788081646,0.019602365791797638,-0.013578495942056179,-0.019451841711997986,-0.020192457363009453,0.01221682783216238,0.08169449120759964,-0.06513894349336624,-0.06570569425821304,0.05045684054493904,0.0018431282369419932,0.005740662571042776,0.04441307857632637,-0.06481757014989853,-0.0033013292122632265,0.04073517024517059,-0.02509496547281742,0.011619355529546738,-0.02413441799581051,0.025068897753953934,-0.06311232596635818,0.007277501747012138,0.04511597752571106,0.014500021934509277,-0.08248715847730637,0.10871385782957077,0.01711863838136196,-0.020399028435349464,-0.03547268360853195,-0.00615588529035449,0.00808884296566248,0.11529547721147537,0.005465428810566664,0.00040173326851800084,-0.0058307466097176075,-0.01738670840859413,-0.030967844650149345,-0.0015059452271088958,-0.027642514556646347,0.028866328299045563,-0.014296476729214191,-0.07303096354007721,0.06497660279273987,-0.015772756189107895,0.010814680717885494,-0.05179964005947113,-0.019607214257121086,-0.0015499228611588478,-0.00896663684