INSERT INTO __mj."Query" ("ID", "Name", "CategoryID", "UserQuestion", "Description", "SQL", "TechnicalDescription", "OriginalSQL", "Feedback", "Status", "QualityRank", "ExecutionCostRank", "__mj_CreatedAt", "__mj_UpdatedAt", "UsesTemplate", "AuditQueryRuns", "CacheEnabled", "CacheTTLMinutes", "CacheMaxSize", "EmbeddingVector", "EmbeddingModelID", "CacheValidationSQL", "SQLDialectID", "Reusable", "ExternalDataSourceID") VALUES ('5044A100-0020-4000-8000-000000000001', 'Sonar: Band Trend', NULL, NULL, 'Per-recompute band mix for a model: one row per (snapshot day, band) with the member count. Deduped per member per day (a same-day re-run writes two history rows; the later one wins). Powers the Overview trend chart and its list of comparable snapshot days.', 'WITH snap AS (
    SELECT h."AnchorRecordID", h."BandID",
        COALESCE(h."AsOfDate", h."ComputedAt")::date AS "SnapshotDay",
        ROW_NUMBER() OVER (PARTITION BY h."AnchorRecordID", COALESCE(h."AsOfDate", h."ComputedAt")::date ORDER BY h."AsOfDate" DESC, h."ComputedAt" DESC) AS rn
    FROM __mj_bizappssonar."ScoreHistory" h
    WHERE h."ScoreModelID" = {{ ModelID | sqlString }}
)
SELECT to_char(s."SnapshotDay", ''YYYY-MM-DD'') AS "SnapshotDay",
       s."BandID"::text AS "BandID",
       COALESCE(b."Label", ''Unbanded'') AS "BandLabel",
       COUNT(*)::int AS "MemberCount"
FROM snap s
LEFT JOIN __mj_bizappssonar."ScoreBand" b ON b."ID" = s."BandID"
WHERE s.rn = 1
GROUP BY s."SnapshotDay", s."BandID", COALESCE(b."Label", ''Unbanded'')
ORDER BY s."SnapshotDay" ASC', NULL, 'WITH snap AS (
    SELECT h."AnchorRecordID", h."BandID",
        COALESCE(h."AsOfDate", h."ComputedAt")::date AS "SnapshotDay",
        ROW_NUMBER() OVER (PARTITION BY h."AnchorRecordID", COALESCE(h."AsOfDate", h."ComputedAt")::date ORDER BY h."AsOfDate" DESC, h."ComputedAt" DESC) AS rn
    FROM __mj_bizappssonar."ScoreHistory" h
    WHERE h."ScoreModelID" = {{ ModelID | sqlString }}
)
SELECT to_char(s."SnapshotDay", ''YYYY-MM-DD'') AS "SnapshotDay",
       s."BandID"::text AS "BandID",
       COALESCE(b."Label", ''Unbanded'') AS "BandLabel",
       COUNT(*)::int AS "MemberCount"
FROM snap s
LEFT JOIN __mj_bizappssonar."ScoreBand" b ON b."ID" = s."BandID"
WHERE s.rn = 1
GROUP BY s."SnapshotDay", s."BandID", COALESCE(b."Label", ''Unbanded'')
