INSERT INTO __mj."Query" ("ID", "Name", "CategoryID", "UserQuestion", "Description", "SQL", "TechnicalDescription", "OriginalSQL", "Feedback", "Status", "QualityRank", "ExecutionCostRank", "__mj_CreatedAt", "__mj_UpdatedAt", "UsesTemplate", "AuditQueryRuns", "CacheEnabled", "CacheTTLMinutes", "CacheMaxSize", "EmbeddingVector", "EmbeddingModelID", "CacheValidationSQL", "SQLDialectID", "Reusable", "ExternalDataSourceID") VALUES ('5044A100-0020-4000-8000-000000000003', 'Sonar: Score Movers', NULL, NULL, 'Biggest individual score movers between two snapshot days for a model: the top N risers and top N fallers by signed score change, with each member''s current score and band. Derived from history snapshots (not the stored Score.Delta, which a no-op re-run resets to zero). Powers the Overview ''biggest drops / gains'' lists at any look-back window.', 'WITH snap AS (
    SELECT h."AnchorRecordID", h."BandID", h."NormalizedScore",
        COALESCE(h."AsOfDate", h."ComputedAt")::date AS "SnapshotDay",
        ROW_NUMBER() OVER (PARTITION BY h."AnchorRecordID", COALESCE(h."AsOfDate", h."ComputedAt")::date ORDER BY h."AsOfDate" DESC, h."ComputedAt" DESC) AS rn
    FROM __mj_bizappssonar."ScoreHistory" h
    WHERE h."ScoreModelID" = {{ ModelID | sqlString }}
      AND COALESCE(h."AsOfDate", h."ComputedAt")::date IN (({{ FromDay | sqlString }})::date, ({{ ToDay | sqlString }})::date)
), diff AS (
    SELECT f."AnchorRecordID",
        (ROUND(t."NormalizedScore"::numeric, 0) - ROUND(f."NormalizedScore"::numeric, 0))::int AS "Delta",
        ROUND(t."NormalizedScore"::numeric, 0)::int AS "CurrentScore",
        t."BandID"
    FROM snap f
    JOIN snap t ON t."AnchorRecordID" = f."AnchorRecordID" AND t."SnapshotDay" = ({{ ToDay | sqlString }})::date AND t.rn = 1
    WHERE f."SnapshotDay" = ({{ FromDay | sqlString }})::date AND f.rn = 1
      AND ROUND(t."NormalizedScore"::numeric, 0) <> ROUND(f."NormalizedScore"::numeric, 0)
), ranked AS (
    SELECT "AnchorRecordID", "Delta", "CurrentScore", "BandID",
        CASE WHEN "Delta" > 0 THEN ''riser'' ELSE ''faller'' END AS "Direction",
        ROW_NUMBER() OVER (PARTITION BY CASE WHEN "Delta" > 0 THEN 1 ELSE 0 END ORDER BY ABS("Delta") DESC) AS rk
    FROM diff
)
SELECT r."AnchorRecordID", r."Delta", r."CurrentScore",
       r."BandID"::text AS "BandID",
       COALESCE(b."Label", ''Unbanded'') AS "BandLabel", r."Direction"
FROM ranked r
LEFT JOIN __mj_bizappssonar."ScoreBand" b ON b."ID" = r."BandID"
WHERE r.rk <= {{ MaxEach | sqlNumber }}
ORDER BY r."Delta" DESC', NULL, 'WITH snap AS (
    SELECT h."AnchorRecordID", h."BandID", h."NormalizedScore",
        COALESCE(h."AsOfDate", h."ComputedAt")::date AS "SnapshotDay",
        ROW_NUMBER() OVER (PARTITION BY h."AnchorRecordID", COALESCE(h."AsOfDate", h."ComputedAt")::date ORDER BY h."AsOfDate" DESC, h."ComputedAt" DESC) AS rn
    FROM __mj_bizappssonar."ScoreHistory" h
    WHERE h."ScoreModelID" = {{ ModelID | sqlString }}
      AND COALESCE(h."AsOfDate", h."ComputedAt")::date IN (({{ FromDay | sqlString }})::date, ({{ ToDay | sqlString }})::date)
), diff AS (
    SELECT f."AnchorRecordID",
        (ROUND(t."NormalizedScore"::numeric, 0) - ROUND(f."NormalizedScore"::numeric, 0))::int AS "Delta",
        ROUND(t."NormalizedScore"::numeric, 0)::int AS "CurrentScore",
        t."BandID"
    FROM snap f
    JOIN snap t ON t."AnchorRecordID" = f."AnchorRecordID" AND t."SnapshotDay" = ({{ ToDay | sqlString }})::date AND t.rn = 1
    WHERE f."SnapshotDay" = ({{ FromDay | sqlString }})::date AND f.rn = 1
      AND ROUND(t."NormalizedScore"::numeric, 0) <> ROUND(f."NormalizedScore"::numeric, 0)
), ranked AS (
    SELECT "AnchorRecordID", "Delta", "CurrentScore", "BandID",
        CASE WHEN "Delta" > 0 THEN ''riser'' ELSE ''faller'' END AS "Direction",
        ROW_NUMBER() OVER (PARTITION BY CASE WHEN "Delta" > 0 THEN 1 ELSE 0 END ORDER BY ABS("Delta") DESC) AS rk
    FROM diff
)
SELECT r."AnchorRecordID", r."Delta", r."CurrentScore",
       r."BandID"::text AS "BandID",
       COALESCE(b."Label", ''Unbanded'') AS "BandLabel", r."Direction"
FROM ranked r
LEFT JOIN __mj_bizappssonar."ScoreBand" b ON b."ID" = r."BandID"
WHERE r.rk <= {{ MaxEach | sqlNumber }}
